// SPDX-License-Identifier: MIT
pragma solidity ^0.8.0;

contract AnonymousVerifier {
    bytes32 public merkleRoot;
    
    // Beležimo iskorišćene nullifier-e da sprečimo dvostruku verifikaciju
    mapping(bytes32 => bool) public nullifierUsed;

    event Verified(bytes32 indexed nullifier, address indexed user);

    constructor(bytes32 _merkleRoot) {
        merkleRoot = _merkleRoot;
    }

    // Funkcija koja proverava Merkle dokaz i vrši anonimnu verifikaciju
    function verifyMembership(
        bytes32 nullifier,
        bytes32[] calldata proof
    ) external {
        require(!nullifierUsed[nullifier], "Nullifier je vec iskoriscen!");

        // Računamo list (leaf) na osnovu nullifier-a i adrese pošiljaoca
        bytes32 leaf = keccak256(abi.encodePacked(nullifier, msg.sender));

        // Verifikacija Merkle dokaza
        bytes32 computedHash = leaf;
        for (uint256 i = 0; i < proof.length; i++) {
            bytes32 proofElement = proof[i];

            if (computedHash <= proofElement) {
                computedHash = keccak256(abi.encodePacked(computedHash, proofElement));
            } else {
                computedHash = keccak256(abi.encodePacked(proofElement, computedHash));
            }
        }

        require(computedHash == merkleRoot, "Verifikacija neuspesna: Niste u stablu!");

        // Označavamo nullifier kao iskorišćen
        nullifierUsed[nullifier] = true;

        emit Verified(nullifier, msg.sender);
    }

    // Funkcija ako bude potrebno ažuriranje korena stabla
    function updateRoot(bytes32 _newRoot) external {
        merkleRoot = _newRoot;
    }
}

